// Delegated events for HTML generated by render/template functions.
(function (global) {
    'use strict';

    const events = global.SanpoEvents || {};

    function setupGeneratedHtmlEventDelegation() {
        if (document.documentElement.dataset.generatedEventsBound === 'true') return;
        document.documentElement.dataset.generatedEventsBound = 'true';

        // Robust fallback for floating person menus.
        // The menu DOM is appended to <body>, so handle its item clicks globally.
        document.addEventListener('click', event => {
            const personActionTarget = event.target.closest?.('[data-person-action]');
            if (!personActionTarget) return;
            event.preventDefault();
            event.stopPropagation();
            global.handleCompactPersonAction?.(
                personActionTarget.dataset.personAction || '',
                global.getActivePersonMenuTarget?.() || null
            );
        }, true);

        const generatedActionHandlers = {
            'edit-capacity': ({ target }) => global.editCapacity?.(target),
            'open-batch': () => openBatchModal(),
            'open-batch-from-sheet': () => { switchView('list'); openBatchModal(); },
            'switch-list': () => switchView('list'),
            'open-settlement-settings': () => global.openSettlementSettings?.(),
            'save-settlement-settings': () => global.saveSettlementSettings?.(),
            'open-settlement-car-edit': ({ target }) => global.openSettlementCarEditor?.(target.dataset.driverName || ''),
            'save-settlement-car-edit': () => global.saveSettlementCarEdit?.(),
            'add-settlement-extra': ({ target }) => global.addSettlementExtra?.(target.dataset.driverName || ''),
            'remove-settlement-extra': ({ target }) => global.removeSettlementExtra?.(target),
            'copy-settlement-text': () => global.copySettlementText?.(),
            'open-route-helper-shortcut': () => global.openRouteDistanceHelperFromShortcut?.(),
            'edit-route-private-origin': () => global.editRoutePrivateOrigin?.(),
            'clear-route-private-origin': () => global.clearRoutePrivateOrigin?.(),
            'save-route-private-origin': () => global.saveRoutePrivateOrigin?.(),
            'cancel-route-private-origin': () => global.cancelRoutePrivateOriginEdit?.(),
            'remove-route-stop': ({ target }) => global.removeRouteStop?.(target),
            'add-route-candidate-to-personal': ({ target }) => global.addRouteCandidateToPersonal?.(target.dataset.routeCandidate || '')
        };
        global.SanpoApp?.registerActions?.(generatedActionHandlers);

        document.addEventListener('click', event => {
            const actionTarget = event.target.closest?.('[data-action]');
            if (!actionTarget) return;
            if (actionTarget.closest?.('.person-pop-menu')) return;
            const action = actionTarget.dataset.action;
            const handled = global.SanpoApp?.runAction?.(action, { event, target: actionTarget, action });
            if (!handled) return;
            event.preventDefault();
        });
    }

    global.SanpoEvents = Object.freeze({
        ...events,
        setupGeneratedHtmlEventDelegation
    });
})(window);
